// Terraform backend key location - computed at CloudResource creation time, immutable thereafter.
//
// ## Background: Terraform State Storage
//
// Terraform stores infrastructure state in a backend. The state file location is
// identified by a "backend key" path that uniquely identifies this resource's state.
//
// ## Backend Key Path Format
//
// Format: .terraform/stacks/{org}/{env}.{kind}.{slug}.tfstate
// Example: ".terraform/stacks/acmecorp/prod.kubernetes_deployment.my-api.tfstate"
//
// This path mirrors Pulumi's DIY backend structure for visual consistency:
//
//	s3://bucket/
//	├── .pulumi/              (Pulumi state)
//	│   └── stacks/
//	│       └── {org}/
//	│           └── {env}.{kind}.{slug}.json
//	└── .terraform/           (Terraform state)
//	    └── stacks/
//	        └── {org}/
//	            └── {env}.{kind}.{slug}.tfstate
//
// This path is used to:
//   - Locate the state file in the backend storage (S3, GCS, Azure, etc.)
//   - Isolate state between different organizations via the {org} folder
//   - Enable state locking for concurrent operations
//   - Provide visual consistency with Pulumi state organization
//
// ## Naming Pattern Consistency
//
// The resource identifier pattern ({env}.{kind}.{slug}) is consistent with Pulumi stack names,
// making it easy to correlate state files across both IaC tools.
//
// ## Why Store This at Creation Time?
//
// Similar to Pulumi stack locations, computing at creation time provides:
//   - Early validation of the backend key path
//   - Auditability (visible in CloudResource spec)
//   - Simplified IaC Runner logic (no runtime computation needed)
//   - Immutable state location for the resource lifecycle
type CloudResourceTerraformBackendLocation struct {
	state protoimpl.MessageState `protogen:"open.v1"`
	// Backend key path.
	//
	// Format: .terraform/stacks/{org}/{env}.{kind}.{slug}.tfstate
	// Example: ".terraform/stacks/acmecorp/prod.kubernetes_deployment.my-api.tfstate"
	//
	// This path identifies the state file location in the backend storage.
	// The actual full path depends on the TerraformBackendCredential configuration,
	// which specifies the bucket, container, or storage account.
	BackendKey    string `protobuf:"bytes,1,opt,name=backend_key,json=backendKey,proto3" json:"backend_key,omitempty"`
	unknownFields protoimpl.UnknownFields
	sizeCache     protoimpl.SizeCache
}

